using Ledgerly.Application.Abstractions; using Ledgerly.Application.Journals; using Ledgerly.Domain.Common; using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.Exceptions; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Application.Bills; public sealed class BillService { private readonly IBillRepository _billRepository; private readonly IContactRepository _contactRepository; private readonly IAccountRepository _accountRepository; private readonly ITaxCodeRepository _taxCodeRepository; private readonly JournalService _journalService; public BillService(IBillRepository billRepository,IContactRepository contactRepository,IAccountRepository accountRepository,ITaxCodeRepository taxCodeRepository,JournalService journalService){_billRepository=billRepository;_contactRepository=contactRepository;_accountRepository=accountRepository;_taxCodeRepository=taxCodeRepository;_journalService=journalService;} public async Task<Result<BillDto>> CreateAsync(CreateBillRequest request,CancellationToken cancellationToken=default){try{var contact=await _contactRepository.GetByIdAsync(request.OrganizationId,request.VendorId,cancellationToken);if(contact is null||contact.ContactType!=ContactType.Vendor)return Result<BillDto>.Failure("Vendor not found.");var currency=new CurrencyCode(request.Currency);var bill=new Bill(request.OrganizationId,request.VendorId,request.BillNumber,request.IssueDate,request.DueDate,currency,request.ExpenseAccountId,request.PayableAccountId);await _billRepository.AddAsync(bill,cancellationToken);return Result<BillDto>.Success(await MapAsync(bill,cancellationToken));}catch(DomainException e){return Result<BillDto>.Failure(e.Message);}} public async Task<Result<BillDto>> GetByIdAsync(Guid organizationId,Guid billId,CancellationToken cancellationToken=default){var bill=await _billRepository.GetByIdAsync(organizationId,billId,cancellationToken);return bill is null?Result<BillDto>.Failure("Bill not found."):Result<BillDto>.Success(await MapAsync(bill,cancellationToken));} public async Task<Result<BillDto>> AddLineAsync(Guid organizationId,Guid billId,AddBillLineRequest request,CancellationToken cancellationToken=default){try{var bill=await _billRepository.GetByIdAsync(organizationId,billId,cancellationToken);if(bill is null)return Result<BillDto>.Failure("Bill not found.");bill.AddLine(request.Description,request.Quantity,new Money(request.UnitPriceAmount,bill.Currency),request.TaxCodeId,new Money(request.DiscountAmount,bill.Currency));await _billRepository.UpdateAsync(bill,cancellationToken);return Result<BillDto>.Success(await MapAsync(bill,cancellationToken));}catch(DomainException e){return Result<BillDto>.Failure(e.Message);}} public async Task<Result<BillDto>> ApproveAsync(Guid organizationId,Guid billId,CancellationToken cancellationToken=default){try{var bill=await _billRepository.GetByIdAsync(organizationId,billId,cancellationToken);if(bill is null)return Result<BillDto>.Failure("Bill not found.");var rates=await RatesAsync(bill,cancellationToken);bill.Approve(rates);var journal=await PostAsync(bill,rates,cancellationToken);if(journal.IsFailure)return Result<BillDto>.Failure(journal.Error!);bill.AttachJournalEntry(journal.Value!.Id);await _billRepository.UpdateAsync(bill,cancellationToken);return Result<BillDto>.Success(await MapAsync(bill,cancellationToken));}catch(DomainException e){return Result<BillDto>.Failure(e.Message);}} public async Task<Result<BillDto>> RecordPaymentAsync(Guid organizationId,Guid billId,RecordBillPaymentRequest request,CancellationToken cancellationToken=default){try{var bill=await _billRepository.GetByIdAsync(organizationId,billId,cancellationToken);if(bill is null)return Result<BillDto>.Failure("Bill not found.");bill.RecordPayment(new Money(request.Amount,bill.Currency));await _billRepository.UpdateAsync(bill,cancellationToken);return Result<BillDto>.Success(await MapAsync(bill,cancellationToken));}catch(DomainException e){return Result<BillDto>.Failure(e.Message);}} private async Task<Result<JournalEntryDto>> PostAsync(Bill bill,Dictionary<Guid,decimal> rates,CancellationToken ct){var draft=await _journalService.CreateDraftAsync(new CreateJournalRequest(bill.OrganizationId,bill.IssueDate,bill.BillNumber,$"Bill {bill.BillNumber}",bill.Currency.Value),ct);if(draft.IsFailure)return Result<JournalEntryDto>.Failure(draft.Error!);var id=draft.Value!.Id;await _journalService.AddLineAsync(bill.OrganizationId,id,new AddJournalLineRequest(bill.ExpenseAccountId,bill.Subtotal.Amount,0m,null),ct);foreach(var g in bill.Lines.Where(l=>l.TaxCodeId.HasValue).GroupBy(l=>l.TaxCodeId!.Value)){var tc=await _taxCodeRepository.GetByIdAsync(bill.OrganizationId,g.Key,ct);if(tc is null)return Result<JournalEntryDto>.Failure("Tax code not found.");var amt=g.Aggregate(new Money(0m,bill.Currency),(s,l)=>s+l.GetTaxAmount(rates[g.Key]));if(amt.Amount>0)await _journalService.AddLineAsync(bill.OrganizationId,id,new AddJournalLineRequest(tc.LiabilityAccountId,amt.Amount,0m,null),ct);}await _journalService.AddLineAsync(bill.OrganizationId,id,new AddJournalLineRequest(bill.PayableAccountId,0m,bill.TotalAmount.Amount,null),ct);return await _journalService.PostAsync(bill.OrganizationId,id,ct);} private async Task<Dictionary<Guid,decimal>> RatesAsync(Bill bill,CancellationToken ct){var d=new Dictionary<Guid,decimal>();foreach(var id in bill.Lines.Where(l=>l.TaxCodeId.HasValue).Select(l=>l.TaxCodeId!.Value).Distinct()){var t=await _taxCodeRepository.GetByIdAsync(bill.OrganizationId,id,ct);if(t is not null)d[id]=t.Rate;}return d;} private async Task<BillDto> MapAsync(Bill bill,CancellationToken ct){var rates=await RatesAsync(bill,ct);var lines=bill.Lines.Select(l=>{var rate=l.TaxCodeId.HasValue&&rates.TryGetValue(l.TaxCodeId.Value,out var r)?r:0m;return new BillLineDto(l.Id,l.Description,l.Quantity,l.UnitPrice.Amount,l.TaxCodeId,l.Discount.Amount,l.GetNetAmount().Amount,l.GetTaxAmount(rate).Amount);}).ToList();return new BillDto(bill.Id,bill.OrganizationId,bill.VendorId,bill.BillNumber,bill.IssueDate,bill.DueDate,bill.Currency.Value,bill.ExpenseAccountId,bill.PayableAccountId,bill.Status,bill.Subtotal.Amount,bill.TaxTotal.Amount,bill.TotalAmount.Amount,bill.AmountPaid.Amount,(bill.TotalAmount-bill.AmountPaid).Amount,bill.JournalEntryId,lines,bill.CreatedAt,bill.UpdatedAt);} }
